mapper.select:
SELECT

FROM t_task t
WHERE t.id = #{taskId}
  AND t.publisher_id = #{publisherId}
  AND t.is_deleted = false
LIMIT 1

SELECT t.id AS taskId, t.title, t.description, AS category, AS status, t.reward, t.location, CASE WHEN t.location_point IS NOT NULL THEN ST_X(t.location_point::geometry) END AS longitude, CASE WHEN t.location_point IS NOT NULL THEN ST_Y(t.location_point::geometry) END AS latitude, u.id AS publisherId, u.nickname AS publisherName, u.avatar_url AS publisherAvatarUrl, u.credit_score AS publisherCreditScore, COALESCE(f.favorite_count, 0) AS favoriteCount, CASE WHEN tf.id IS NULL THEN FALSE ELSE TRUE END AS favorited, t.create_time AS createdAt, t.update_time AS updatedAt FROM t_task t JOIN u_user u ON u.id = t.publisher_id AND u.is_deleted = false LEFT JOIN ( SELECT task_id, COUNT(*) AS favorite_count FROM t_task_favorite GROUP BY task_id ) f ON f.task_id = t.id LEFT JOIN t_task_favorite tf ON tf.task_id = t.id AND tf.user_id = #{viewerId} WHERE t.is_deleted = false
AND t.category = #{category}
AND t.publisher_id = #{publisherId}
AND (t.title ILIKE CONCAT('%', #{keyword}, '%') OR t.description ILIKE CONCAT('%', #{keyword}, '%'))
ORDER BY COALESCE(f.favorite_count, 0) DESC, t.create_time DESC
ORDER BY t.create_time DESC
OFFSET #{offset} LIMIT #{size}

SELECT COUNT(1)
FROM t_task t
WHERE t.is_deleted = false

    AND t.category = #{category}


    AND t.publisher_id = #{publisherId}


    AND (t.title ILIKE CONCAT('%', #{keyword}, '%') OR t.description ILIKE CONCAT('%', #{keyword}, '%'))

SELECT t.id AS taskId, t.title, t.description, AS category, AS status, t.reward, t.location, CASE WHEN t.location_point IS NOT NULL THEN ST_X(t.location_point::geometry) END AS longitude, CASE WHEN t.location_point IS NOT NULL THEN ST_Y(t.location_point::geometry) END AS latitude, u.id AS publisherId, u.nickname AS publisherName, u.avatar_url AS publisherAvatarUrl, u.credit_score AS publisherCreditScore, COALESCE(f.favorite_count, 0) AS favoriteCount, TRUE AS favorited, t.create_time AS createdAt, t.update_time AS updatedAt FROM t_task_favorite tf JOIN t_task t ON t.id = tf.task_id AND t.is_deleted = false JOIN u_user u ON u.id = t.publisher_id AND u.is_deleted = false LEFT JOIN ( SELECT task_id, COUNT(*) AS favorite_count FROM t_task_favorite GROUP BY task_id ) f ON f.task_id = t.id WHERE tf.user_id = #{userId}
AND t.category = #{category}
AND (t.title ILIKE CONCAT('%', #{keyword}, '%') OR t.description ILIKE CONCAT('%', #{keyword}, '%'))
ORDER BY COALESCE(f.favorite_count, 0) DESC, tf.create_time DESC
ORDER BY tf.create_time DESC
OFFSET #{offset} LIMIT #{size}

SELECT COUNT(1)
FROM t_task_favorite tf
JOIN t_task t ON t.id = tf.task_id AND t.is_deleted = false
WHERE tf.user_id = #{userId}

    AND t.category = #{category}


    AND (t.title ILIKE CONCAT('%', #{keyword}, '%') OR t.description ILIKE CONCAT('%', #{keyword}, '%'))

